import dayjs from "dayjs";
import {
  type ReactNode,
  useCallback,
  useContext,
  useMemo,
  useState,
} from "react";
import { useWindowSize } from "react-use";

import type { TransactionDirection } from "@dfp/bw-isomorphic-enums";

import { useTimePeriodControls } from "../../../TimePeriodContext.tsx";
import type { CategoryType } from "../../types/index.ts";
import { useCashflowTable } from "../CashflowTableContext.tsx";
import { CategoryDetailPopover } from "./CategoryDetailPopover.tsx";
import {
  CategoryDetailPanelContext,
  type CategoryDetailPanelParams,
} from "./categoryDetailPanel.context.ts";

type UseOpenCategoryDetailParams = {
  category: CategoryType;
  categoryLabel: ReactNode;
  direction: TransactionDirection;
};

type CategoryDetailPopoverProviderProps = {
  children: ReactNode;
};

export function CategoryDetailPopoverProvider({
  children,
}: CategoryDetailPopoverProviderProps) {
  const [params, setParams] = useState<CategoryDetailPanelParams | null>(null);

  // MUI Popover's anchorPosition only accepts { top, left } — no "right" property.
  // We derive "right: 24px" from window width in the only format the API supports.
  const { width } = useWindowSize();
  const anchorPosition = useMemo(
    () => ({ left: width - 24, top: 24 }),
    [width],
  );

  const { data } = useCashflowTable();
  const { setPeriod } = useTimePeriodControls();

  const handleChangeColumn = useCallback(
    (index: number) => {
      const period = data?.periods[index];
      if (!period) return;
      setPeriod(dayjs(period.dateFrom));
    },
    [data, setPeriod],
  );

  const openCategoryDetail = useCallback(
    (newParams: CategoryDetailPanelParams) => {
      if (!data?.periods) return;

      const period = data.periods[newParams.columnIndex];
      if (period) setPeriod(dayjs(period.dateFrom));

      setParams(newParams);
    },
    [data, setPeriod],
  );

  const contextValue = useMemo(
    () => ({ openCategoryDetail }),
    [openCategoryDetail],
  );

  return (
    <CategoryDetailPanelContext.Provider value={contextValue}>
      {children}

      <CategoryDetailPopover
        anchorPosition={anchorPosition}
        onChangeColumn={handleChangeColumn}
        onClose={() => setParams(null)}
        open={params != null}
        params={params}
      />
    </CategoryDetailPanelContext.Provider>
  );
}

export function useOpenCategoryDetail({
  category,
  categoryLabel,
  direction,
}: UseOpenCategoryDetailParams) {
  const context = useContext(CategoryDetailPanelContext);
  if (!context) {
    throw new Error(
      "useOpenCategoryDetail must be used within CategoryDetailPanelProvider",
    );
  }

  const { openCategoryDetail } = context;

  return useCallback(
    (columnIndex: number) => {
      openCategoryDetail({ category, categoryLabel, columnIndex, direction });
    },
    [openCategoryDetail, category, categoryLabel, direction],
  );
}

